-- Tabela: Klienci
CREATE TABLE [dbo].[Klienci] (
    Klient_ID INT PRIMARY KEY,
    Imie NVARCHAR(50) NOT NULL,
    Nazwisko NVARCHAR(50) NOT NULL,
    Adres_Email NVARCHAR(100) NULL,
    Miasto NVARCHAR(50),
    Adres_Zamieszkania NVARCHAR(200),
    Status VARCHAR(20) DEFAULT 'Nowy' CHECK (Status IN ('Nowy', 'VIP', 'Staly'))
);


-- Tabela: Klienci_Dane_Dodatkowe
CREATE TABLE [dbo].[Klienci_Dane_Dodatkowe] (
    Klient_ID INT PRIMARY KEY,
    Data_Urodzenia DATE NULL,
    Zawod NVARCHAR(200) NOT NULL,
    Zgoda_Na_Newsletter NVARCHAR(3) NULL,
    FOREIGN KEY (Klient_ID) REFERENCES Klienci(Klient_ID),
);


-- Tabela: Kategorie produkt w
CREATE TABLE [dbo].[Kategorie] (
    Kategoria_ID INT PRIMARY KEY,
    Nazwa_Kategorii NVARCHAR(100) NOT NULL
);


-- Tabela: Podkategorie produkt w
CREATE TABLE [dbo].[Podkategorie](
   Podkategoria_ID INT NOT NULL  PRIMARY KEY,
   Kategoria_ID INT NOT NULL,
   Nazwa_Podkategorii NVARCHAR(100) NOT NULL,
   FOREIGN KEY (Kategoria_ID) REFERENCES Kategorie(Kategoria_ID)
);


-- Tabela: Produkty
CREATE TABLE [dbo].[Produkty] (
    Produkt_ID INT PRIMARY KEY,
    Nazwa_Produktu NVARCHAR(100) NOT NULL,
    Marka NVARCHAR(100) NULL,
    Kolor NVARCHAR(30),
    Podkategoria_ID INT NOT NULL,
    Cena_Zakupu DECIMAL(10,2) NOT NULL,
    Marza_Procent DECIMAL(5,2) NOT NULL,        -- marza sklepu
    Cena_Sprzedazy DECIMAL(10,2) NOT NULL,      -- cena widoczna dla klienta, powiekszona o marze, rabaty sa naliczane na etapie kompletowania zamowienia
    FOREIGN KEY (Podkategoria_ID) REFERENCES Podkategorie(Podkategoria_ID)
);


-- Tabela: Pracownicy
CREATE TABLE [dbo].[Pracownicy] (
    Pracownik_ID INT PRIMARY KEY,
    Imie NVARCHAR(50) NOT NULL,
    Nazwisko NVARCHAR(50) NOT NULL,
    Rola NVARCHAR(100) NOT NULL,
    Kierownik_ID INT NULL,
    FOREIGN KEY (Kierownik_ID) REFERENCES Pracownicy(Pracownik_ID),
    Status_Zatrudnienia VARCHAR(20) DEFAULT 'Aktywny' CHECK (Status_Zatrudnienia IN ('Aktywny', 'Zwolniony')),
    Data_Zatrudnienia DATE NOT NULL,
    Data_Zakonczenia DATE NULL
);


-- Tabela: Zam wienia
CREATE TABLE [dbo].[Zamowienia] (
    Zamowienie_ID INT PRIMARY KEY,
    Klient_ID INT NOT NULL,
    ID_Pracownika_Obsluga INT NULL,        -- pracownik zatwierdzaj cy / kontaktowy
    ID_Pracownika_Pakowanie INT NULL,      -- magazynier pakuj cy
    Data_Zlozenia_Zamowienia DATETIME NOT NULL,    
    Data_Wyslania_Zamowienia DATETIME NULL,
    Status VARCHAR(20) DEFAULT 'Nowe' CHECK (Status IN ('Nowe', 'W realizacji', 'Zrealizowane')),
    FOREIGN KEY (Klient_ID) REFERENCES Klienci(Klient_ID),
    FOREIGN KEY (ID_Pracownika_Obsluga) REFERENCES Pracownicy(Pracownik_ID),
    FOREIGN KEY (ID_Pracownika_Pakowanie) REFERENCES Pracownicy(Pracownik_ID)
);


-- Tabela: Zam wione Produkty (tabela   cz ca zam wienia z produktami)
CREATE TABLE [dbo].[Zamowione_Produkty] (
    Zamowienie_ID INT NOT NULL,
    Produkt_ID INT NOT NULL,
    Ilosc INT NOT NULL,
    Cena_Zakupu DECIMAL(10,2) NOT NULL,         -- cena nie widoczna dla klienta
    Marza_Procent DECIMAL(5,2) NOT NULL,        -- marza sklepu
    Rabat_Procent DECIMAL(5,2) DEFAULT 0.00,    -- przyznany rabat
    Cena_Sprzedazy DECIMAL(10,2) NOT NULL,      -- cena widoczna dla klienta, pierw powiekszona o marze, potem zmniejszona o rabat
    PRIMARY KEY (Zamowienie_ID, Produkt_ID),
    FOREIGN KEY (Zamowienie_ID) REFERENCES Zamowienia(Zamowienie_ID),
    FOREIGN KEY (Produkt_ID) REFERENCES Produkty(Produkt_ID)
);





update z set Miasto = 'Jeffreyton'
FROM [Sklep_internetowy].[dbo].[Klienci] z
where Miasto Like 'North%';

update z set Miasto = 'Madisonton'
FROM [Sklep_internetowy].[dbo].[Klienci] z
where Miasto Like 'Lake%';

update z set Adres_Email = NULL
FROM Klienci z
where Klient_ID IN (1,5,80,99);












UPDATE p 
SET Kolor = NULL
FROM [Sklep_internetowy].[dbo].[Produkty] p
WHERE Kolor = 'NULL';






